import psycopg2

def connect_to_db():
    try: 
        conn = psycopg2.connect(host="localhost", database="YourDatabaseName", user="YourUsername", password="YourPassword")
         # create a cursor object using the cursor() method
        cur = conn.cursor()    
        return conn,cur 
    except (Exception, psycopg2.Error) as error :   
        print ("Error while connecting to PostgreSQL", error)  

def search_users(username=None, email=None, role=None, status=None):
    # Connect to your postgres DB
    conn, cur = connect_to_db()
    
    query = "SELECT * FROM Users WHERE 1=1"
    if username:
        query += f" AND Username = '{username}'"
        
    if email:
        query += f" AND Email = '{email}'"
     
    if role:
        query += f" AND Role = '{role}'"
    
    if status: 
        query += f" AND Status = '{status}'"
        
    # execute the query
    cur.execute(query)
    users = cur.fetchall()  
    conn.close()     
    return users